svg.script:

(function() {
  'use strict';

  var backendInput = document.getElementById('backend');
  var urlInput = document.getElementById('url');
  var goBtn = document.getElementById('go');
  var newTabCheckbox = document.getElementById('newtab');
  var statusGroup = document.getElementById('status-group');
  var statusText = document.getElementById('status-text');
  var infoBox = document.querySelector('.info-box');
  var infoTexts = document.querySelectorAll('.info-title, .info-text, .note-text');
  var infoLine = document.querySelector('line');
  var proxyContainer = document.getElementById('proxy-container');
  var proxyFrame = document.getElementById('proxy-frame');

  function showStatus(text) {
    statusGroup.style.display = 'block';
    statusText.textContent = text;
  }

  function hideStatus() {
    statusGroup.style.display = 'none';
  }

  function navigate() {
    var url = urlInput.value.trim();
    var backend = backendInput.value.trim();

    if (!url) {
      showStatus('Please enter a URL');
      return;
    }

    if (!backend) {
      backend = window.location.origin;
    }
    backend = backend.replace(/\/$/, '');

    if (!url.match(/^https?:\/\//)) {
      url = 'https://' + url;
    }

    showStatus('Loading ' + url + '...');

    try {
      // Base64 encode
      var base64 = btoa(url);
      var encoded = backend + '/~/' + base64;

      console.log('Encoded:', encoded);

      // Check if open in new tab
      if (newTabCheckbox && newTabCheckbox.checked) {
        window.open(encoded, '_blank');
        hideStatus();
        return;
      }

      // Hide info elements
      infoBox.style.display = 'none';
      for (var i = 0; i < infoTexts.length; i++) {
        infoTexts[i].style.display = 'none';
      }
      if (infoLine) infoLine.style.display = 'none';

      // Show iframe
      proxyContainer.style.display = 'block';
      proxyFrame.setAttribute('src', encoded);
      hideStatus();
    } catch (e) {
      showStatus('Error: ' + e.message);
    }
  }

  goBtn.addEventListener('click', navigate);
  urlInput.addEventListener('keypress', function(e) {
    if (e.key === 'Enter') navigate();
  });

  // Parse hash for config
  var hash = window.location.hash;
  if (hash && hash.length > 1) {
    var config = hash.substring(1);
    var parts = config.split('/');
    for (var j = 0; j < parts.length; j++) {
      var kv = parts[j].split('=');
      if (kv[0] === 'backend' && kv[1]) {
        backendInput.value = decodeURIComponent(kv[1]);
      }
      if (kv[0] === 'url' && kv[1]) {
        urlInput.value = decodeURIComponent(kv[1]);
        navigate();
      }
    }
  }
})();
